import React from 'react';

export default function Hero() {
  return (
    <section className="relative w-full mt-[72px] h-[70vh] min-h-[500px] overflow-visible bg-white px-4 sm:px-6 lg:px-8 pb-4 pt-4">
      {/* Video Background Container */}
      <div className="relative w-full h-full overflow-hidden rounded-[20px] rounded-br-[120px] shadow-lg">
        {/* Responsive Vimeo Background iframe matching object-cover behavior */}
        <div className="absolute inset-0 w-full h-full pointer-events-none">
          <iframe 
            src="https://player.vimeo.com/video/1155803167?background=1&autoplay=1&loop=1&muted=1" 
            className="absolute top-1/2 left-1/2 w-[200vw] h-[200vw] max-w-none transform -translate-x-1/2 -translate-y-1/2 aspect-video pointer-events-none"
            style={{ width: '150vh', minWidth: '100%', minHeight: '100%', height: '56.25vw' }}
            frameBorder="0" 
            allow="autoplay; fullscreen; picture-in-picture"
          ></iframe>
        </div>

        {/* Very light overlay just to adjust contrast if needed */}
        <div className="absolute inset-0 bg-black/10"></div>

        {/* Ticker at the bottom of the hero video */}
        <div className="absolute bottom-0 left-0 w-full bg-transparent overflow-hidden py-4 z-10 pointer-events-none">
          <div className="marquee-track flex whitespace-nowrap text-white" style={{ animationDuration: '40s' }}>
            {[...Array(6)].map((_, i) => (
              <span key={i} className="font-display text-4xl sm:text-6xl tracking-widest uppercase mr-8 drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)]">
                DELIVERY - PICK UP - BRICK OVEN PIZZA - PIZZA WITH LOVE -
              </span>
            ))}
          </div>
        </div>
      </div>

      {/* Massive Overlapping Half-Pizza Image */}
      <img
        src="https://images.unsplash.com/photo-1593504049359-74330189a345?w=800&auto=format&fit=crop"
        alt="Massive Pizza"
        className="hidden lg:block absolute -bottom-[650px] -right-[10px] w-[500px] h-auto object-contain z-20 drop-shadow-2xl rounded-full mix-blend-multiply opacity-0 sm:opacity-100"
        style={{ clipPath: 'polygon(0 0, 100% 0, 100% 100%, 0 100%)', filter: 'contrast(1.2) saturate(1.2)' }}
      />
    </section>
  );
}
